def _backup(path: Path, root: Path, backup_root: Path) -> str | None:
    if not path.exists():
        return None
    relative = path.relative_to(root)
    target = backup_root / relative
    target.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(path, target)
    return relative.as_posix()


def main() -> int:
    root = Path.cwd()
    timestamp = time.strftime("%Y%m%dT%H%M%SZ", time.gmtime())
    backup_root = root / "tools" / f"_patch_backup_{PATCH_ID}_{timestamp}"
    backed_up: list[str] = []
    written: list[str] = []
    for relative, content in PAYLOADS.items():
        path = root / relative
        backup_rel = _backup(path, root, backup_root)
        if backup_rel:
            backed_up.append(backup_rel)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(content, encoding="utf-8", newline="\n")
        written.append(relative)
    if not backed_up and backup_root.exists():
        shutil.rmtree(backup_root)
    compile_errors: dict[str, str] = {}
    for relative in PAYLOADS:
        if relative.endswith(".py"):
            try:
                py_compile.compile(str(root / relative), doraise=True)
            except py_compile.PyCompileError as exc:
                compile_errors[relative] = str(exc)
    result = {
        "applied": not compile_errors,
        "patch_id": PATCH_ID,
        "patch_version": PATCH_VERSION,
        "patch_name": PATCH_NAME,
        "written_files": written,
        "backed_up_files": backed_up,
        "backup_root": str(backup_root.relative_to(root)) if backed_up else "",
        "py_compile_ok": not compile_errors,
        "compile_errors": compile_errors,
        "approved_for_live_real": False,
        "approved_for_paper_transition": False,
        "approved_for_exchange_submit": False,
        "approved_for_runtime_overlay": False,
        "trading_action_performed": False,
        "training_performed": False,
        "reload_performed": False,
        "exchange_submit_performed": False,
        "runtime_overlay_activated": False,
        "destructive_cleanup_performed": False,
    }
    print(json.dumps(result, indent=2, sort_keys=True, ensure_ascii=False))
    return 0 if not compile_errors else 1


if __name__ == "__main__":
    raise SystemExit(main())
